import React, { useState, useEffect, useCallback } from 'react';
import { useSearchParams, useNavigate } from 'react-router-dom';
import Navbar from '../components/shared/Navbar';
import ProviderCard from '../components/shared/ProviderCard';
import { providerAPI } from '../utils/api';
import toast from 'react-hot-toast';

const CATEGORIES = {
  Electrician: ['Wiring', 'Fan Repair', 'Switchboard Fixing', 'AC Installation', 'MCB Repair', 'CCTV Installation'],
  Plumber: ['Pipe Repair', 'Tap Fixing', 'Bathroom Fitting', 'Water Tank Cleaning', 'Drain Cleaning'],
  Carpenter: ['Furniture Repair', 'Door Fitting', 'Cupboard Making', 'Wood Polishing'],
  Painter: ['Wall Painting', 'Waterproofing', 'Texture Painting', 'Exterior Painting'],
  Cleaner: ['Home Cleaning', 'Office Cleaning', 'Sofa Cleaning', 'Deep Cleaning'],
  ACTechnician: ['AC Installation', 'AC Service', 'AC Gas Refill', 'AC Repair'],
};
const CAT_ICONS = { Electrician: '⚡', Plumber: '🔧', Carpenter: '🪚', Painter: '🎨', Cleaner: '🧹', ACTechnician: '❄️' };

export default function SearchPage() {
  const [searchParams, setSearchParams] = useSearchParams();
  const navigate = useNavigate();

  const [providers, setProviders] = useState([]);
  const [loading, setLoading] = useState(false);
  const [total, setTotal] = useState(0);
  const [userLocation, setUserLocation] = useState(null);

  const [filters, setFilters] = useState({
    serviceCategory: searchParams.get('category') || '',
    skill: searchParams.get('skill') || '',
    sort: 'rating',
    radius: 10,
    minRating: '',
    maxPrice: '',
    page: 1,
  });
  const [q, setQ] = useState(searchParams.get('q') || '');

  // Get user's location
  useEffect(() => {
    navigator.geolocation?.getCurrentPosition(
      ({ coords }) => setUserLocation({ lat: coords.latitude, lng: coords.longitude }),
      () => toast('Enable location for nearby results', { icon: '📍' })
    );
  }, []);

  const fetchProviders = useCallback(async () => {
    setLoading(true);
    try {
      const params = { ...filters };
      if (userLocation) { params.lat = userLocation.lat; params.lng = userLocation.lng; }
      const { data } = await providerAPI.search(params);
      setProviders(data.data);
      setTotal(data.total);
    } catch {
      toast.error('Failed to load providers');
    } finally {
      setLoading(false);
    }
  }, [filters, userLocation]);

  useEffect(() => { fetchProviders(); }, [fetchProviders]);

  const setFilter = (key, value) => setFilters(f => ({ ...f, [key]: value, page: 1 }));

  const activeSkills = filters.serviceCategory ? CATEGORIES[filters.serviceCategory] || [] : [];

  return (
    <div style={{ minHeight: '100vh' }}>
      <Navbar />

      <div className="page-container" style={{ paddingTop: 32, paddingBottom: 48 }}>
        {/* Search + Location bar */}
        <div style={{ display: 'flex', gap: 12, marginBottom: 28, flexWrap: 'wrap' }}>
          <div style={{ flex: 1, minWidth: 200, position: 'relative' }}>
            <input className="form-input" placeholder="Search services..." value={q}
              onChange={e => setQ(e.target.value)}
              onKeyDown={e => e.key === 'Enter' && setFilter('q', q)} style={{ paddingRight: 44 }} />
            <button onClick={() => setFilter('q', q)} style={{ position: 'absolute', right: 12, top: '50%', transform: 'translateY(-50%)', background: 'none', border: 'none', cursor: 'pointer', color: 'var(--accent)', fontSize: 18 }}>🔍</button>
          </div>
          <button className="btn btn-secondary" onClick={() => {
            navigator.geolocation?.getCurrentPosition(({ coords }) => {
              setUserLocation({ lat: coords.latitude, lng: coords.longitude });
              toast.success('Location updated!');
            });
          }}>📍 Use My Location</button>
        </div>

        <div style={{ display: 'flex', gap: 24 }}>
          {/* ── Sidebar Filters ── */}
          <div style={{ width: 240, flexShrink: 0 }}>
            <div className="card" style={{ position: 'sticky', top: 80 }}>
              <h3 style={{ fontWeight: 700, marginBottom: 20, fontSize: 15 }}>Filters</h3>

              {/* Category */}
              <div className="form-group" style={{ marginBottom: 16 }}>
                <label className="form-label">Category</label>
                <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
                  <button className={`btn btn-sm ${!filters.serviceCategory ? 'btn-primary' : 'btn-ghost'}`}
                    onClick={() => setFilter('serviceCategory', '')}>All Categories</button>
                  {Object.keys(CATEGORIES).map(cat => (
                    <button key={cat}
                      className={`btn btn-sm ${filters.serviceCategory === cat ? 'btn-primary' : 'btn-ghost'}`}
                      style={{ justifyContent: 'flex-start' }}
                      onClick={() => { setFilter('serviceCategory', cat); setFilter('skill', ''); }}>
                      {CAT_ICONS[cat]} {cat}
                    </button>
                  ))}
                </div>
              </div>

              {/* Skills */}
              {activeSkills.length > 0 && (
                <div className="form-group" style={{ marginBottom: 16 }}>
                  <label className="form-label">Sub-Service</label>
                  <select className="form-select" value={filters.skill} onChange={e => setFilter('skill', e.target.value)}>
                    <option value="">All Skills</option>
                    {activeSkills.map(s => <option key={s} value={s}>{s}</option>)}
                  </select>
                </div>
              )}

              {/* Radius */}
              <div className="form-group" style={{ marginBottom: 16 }}>
                <label className="form-label">Radius: {filters.radius} km</label>
                <input type="range" min="1" max="50" value={filters.radius}
                  onChange={e => setFilter('radius', e.target.value)}
                  style={{ width: '100%', accentColor: 'var(--accent)' }} />
              </div>

              {/* Min Rating */}
              <div className="form-group" style={{ marginBottom: 16 }}>
                <label className="form-label">Min Rating</label>
                <select className="form-select" value={filters.minRating} onChange={e => setFilter('minRating', e.target.value)}>
                  <option value="">Any</option>
                  {[4.5, 4, 3.5, 3].map(r => <option key={r} value={r}>{'★'.repeat(Math.floor(r))} {r}+</option>)}
                </select>
              </div>

              {/* Sort */}
              <div className="form-group" style={{ marginBottom: 16 }}>
                <label className="form-label">Sort By</label>
                <select className="form-select" value={filters.sort} onChange={e => setFilter('sort', e.target.value)}>
                  <option value="rating">⭐ Top Rated</option>
                  <option value="distance">📍 Nearest</option>
                  <option value="price">💰 Lowest Price</option>
                </select>
              </div>

              {/* Max Price */}
              <div className="form-group">
                <label className="form-label">Max Price (₹)</label>
                <input className="form-input" type="number" placeholder="e.g. 1000" value={filters.maxPrice}
                  onChange={e => setFilter('maxPrice', e.target.value)} />
              </div>

              <button className="btn btn-ghost btn-sm" style={{ marginTop: 16, width: '100%' }}
                onClick={() => setFilters({ serviceCategory: '', skill: '', sort: 'rating', radius: 10, minRating: '', maxPrice: '', page: 1 })}>
                Reset Filters
              </button>
            </div>
          </div>

          {/* ── Results ── */}
          <div style={{ flex: 1 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 }}>
              <div style={{ color: 'var(--text-secondary)', fontSize: 14 }}>
                {loading ? 'Searching...' : `${total} provider${total !== 1 ? 's' : ''} found`}
                {!userLocation && <span style={{ color: 'var(--warning)', marginLeft: 8, fontSize: 12 }}>⚠️ Enable location for distance info</span>}
              </div>
            </div>

            {loading ? (
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: 16 }}>
                {[...Array(6)].map((_, i) => (
                  <div key={i} className="skeleton" style={{ height: 200 }} />
                ))}
              </div>
            ) : providers.length === 0 ? (
              <div className="empty-state card">
                <div className="empty-state-icon">🔍</div>
                <h3>No providers found</h3>
                <p>Try adjusting your filters or expanding the search radius</p>
                <button className="btn btn-primary" style={{ marginTop: 16 }}
                  onClick={() => setFilters(f => ({ ...f, radius: 50, minRating: '', maxPrice: '' }))}>
                  Expand Search
                </button>
              </div>
            ) : (
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: 16 }}>
                {providers.map(p => <ProviderCard key={p._id} provider={p} />)}
              </div>
            )}

            {/* Pagination */}
            {total > 20 && (
              <div style={{ display: 'flex', justifyContent: 'center', gap: 8, marginTop: 32 }}>
                <button className="btn btn-ghost btn-sm" disabled={filters.page === 1}
                  onClick={() => setFilters(f => ({ ...f, page: f.page - 1 }))}>← Prev</button>
                <span style={{ padding: '8px 16px', color: 'var(--text-secondary)', fontSize: 14 }}>
                  Page {filters.page}
                </span>
                <button className="btn btn-ghost btn-sm" disabled={providers.length < 20}
                  onClick={() => setFilters(f => ({ ...f, page: f.page + 1 }))}>Next →</button>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
